INSERT INTO CHAMP_SKIN_INFO (
	CHAMP_SKIN_NO, CHAMP_NO, CHAMP_SKIN_NAME, CHAMP_SKIN_IMG
) VALUES (
	SEQ_CHAMP_SKIN_NO.NEXTVAL, #{champNo},
	#{champSkinName}, #{champSkinImg}
)

INSERT INTO TALENT_INFO (
	TALENT_NO, RUNE_NO, TALENT_NAME, 
	TALENT_INFO, TALENT_IMG
) VALUES (
	SEQ_TALENT_NO.NEXTVAL, #{runeNo}, #{talentName}, 
	#{talentInfo}, #{talentImg}
)
